// RUN: objc3c -fobjc-version=3 --emit-module IFC55B.objcmod --emit-interface IFC55B.obji %s
// RUN: objc3c --verify-interface IFC55B.objcmod IFC55B.obji %s
#define NS_ASSUME_NONNULL_BEGIN _Pragma("clang assume_nonnull begin")
#define NS_ASSUME_NONNULL_END _Pragma("clang assume_nonnull end")
#define OBJC3_UNSAFE_SENDABLE __attribute__((objc_unsafe_sendable))
#define OBJC3_NONISOLATED __attribute__((objc_nonisolated))
NS_ASSUME_NONNULL_BEGIN
OBJC3_UNSAFE_SENDABLE
@interface IFC55NormalizedBox : NSObject
- (id _Nullable)currentToken OBJC3_NONISOLATED;
@end
NS_ASSUME_NONNULL_END

expect.canonical_interface:
#pragma objc assume_nonnull begin
__attribute__((objc_unsafe_sendable))
@interface IFC55NormalizedBox : NSObject
- (id _Nullable)currentToken __attribute__((objc_nonisolated));
@end
#pragma objc assume_nonnull end
